        # If a dedicated metadata/container attribute exists, ensure its keys are accessible
        # at the top level for filtering (without overwriting existing keys).
        for meta_attr in ("metadata", "meta", "attrs"):
            if hasattr(res, meta_attr):
                meta_val = getattr(res, meta_attr)
                if isinstance(meta_val, dict):
