                        base.setdefault(k, v)
                break

        dict_items.append(base)

    # Build a list of filter condition objects for the engine.
    # filter_specs format: {field: {operator: value}}
    conditions = []
    for field, ops in filter_specs.items():
        if not isinstance(ops, dict):
            raise ValueError(
                f"Filter specification for field '{field}' must be a dict "
                f"of operator -> value, got: {type(ops)}"
            )
        for op, value in ops.items():
            conditions.append({"field": field, "operator": op, "value": value})

    if not conditions:
        return search_results

    # Initialize and configure metadata filter engine
    engine = MetadataFilterEngine()
    engine.set_logic(logic)
    for cond in conditions:
        engine.add_condition(
            field=cond["field"],
            operator=cond["operator"],
            value=cond["value"],
        )

    # Evaluate each dict item and keep those that match
    filtered_results: List[SearchResult] = []
    for res, item in zip(search_results, dict_items):
        if engine.matches(item):
            filtered_results.append(res)

    return filtered_results
