            Example: {"category": "tech", "rating": 5.0}
            All criteria must match (AND logic)

    Returns:
        List of passage dictionaries that match all criteria. Returns an empty
        list if no passages match or if the passages file does not exist.
    """
    # Initialize the PassageManager for the given index
    try:
        pm = PassageManager(index_path)
    except Exception:
        # If PassageManager cannot be initialized, treat as no passages
        return []

    # Try to locate the passages file used by this index. The concrete path is
    # managed by leann, but PassageManager typically exposes the underlying
    # storage path, so we use that if available. Otherwise, we fall back to
    # a common default filename next to the index.
    passages_path: Path

    # If PassageManager exposes a path or config, use it
    passages_path = None  # type: ignore[assignment]
    if hasattr(pm, "passages_path"):
        passages_path = Path(getattr(pm, "passages_path"))  # type: ignore[assignment]
    elif hasattr(pm, "config") and isinstance(getattr(pm, "config"), dict):
        cfg = getattr(pm, "config")
        possible = cfg.get("passages_path") or cfg.get("passages_file")
        if possible:
            passages_path = Path(possible)

    # Fallback: assume a JSONL/JSON file next to the index path
    if passages_path is None:
        base = Path(index_path)
        if base.is_dir():
            # common default names
            for name in ("passages.jsonl", "passages.json", "passages.ndjson"):
                candidate = base / name
                if candidate.exists():
                    passages_path = candidate
                    break
        else:
            # if index is a file, look in its parent directory
            parent = base.parent
            for name in ("passages.jsonl", "passages.json", "passages.ndjson"):
                candidate = parent / name
                if candidate.exists():
                    passages_path = candidate
                    break

    # If we still don't know where passages are stored, attempt to ask the
    # PassageManager directly if it exposes a list/iterator of passages.
    passages: List[Dict[str, Any]] = []
    if passages_path is None:
        # Try attribute-based access as a last resort
        if hasattr(pm, "get_all_passages") and callable(getattr(pm, "get_all_passages")):
            try:
                passages = list(getattr(pm, "get_all_passages")())
            except Exception:
