            try:
                passages_attr = getattr(pm, "passages")
                # Could already be a list or an iterator
                if isinstance(passages_attr, list):
                    passages = passages_attr
                else:
                    passages = list(passages_attr)
            except Exception:
                return []
        else:
            # No way to find or load passages
            return []
    else:
        # If the passages file does not exist, return empty list
        if not passages_path.exists():
            return []

        # Load passages from file; support JSONL/NDJSON and JSON list
        try:
            suffix = passages_path.suffix.lower()
            if suffix in [".jsonl", ".ndjson"]:
                with passages_path.open("r", encoding="utf-8") as f:
                    for line in f:
                        line = line.strip()
                        if not line:
                            continue
                        passages.append(json.loads(line))
            elif suffix == ".json":
                with passages_path.open("r", encoding="utf-8") as f:
                    data = json.load(f)
                    # either a list of passages or an object with a key
                    if isinstance(data, list):
                        passages = data
                    elif isinstance(data, dict):
                        # common key names
                        for key in ("passages", "items", "data"):
                            if key in data and isinstance(data[key], list):
                                passages = data[key]
                                break
                        if not passages and "passages" in data:
                            passages = data["passages"]  # type: ignore[assignment]
            else:
                # Unsupported extension; attempt JSONL-style as a fallback
                with passages_path.open("r", encoding="utf-8") as f:
                    for line in f:
                        line = line.strip()
                        if not line:
                            continue
                        passages.append(json.loads(line))
        except (OSError, json.JSONDecodeError):
            # On any IO/parse error, treat as no passages
            return []

    # Apply AND-filter on metadata_criteria with exact (==) matching
    if not metadata_criteria:
        # If no criteria are provided, return all passages
        return passages

    filtered: List[Dict[str, Any]] = []
    for p in passages:
        # metadata could be directly on passage dict or under "metadata" key
        meta = p.get("metadata", p)
        if not isinstance(meta, dict):
            continue

        match = True
        for key, value in metadata_criteria.items():
            if key not in meta or meta.get(key) != value:
                match = False
                break

        if match:
            filtered.append(p)

    return filtered
